Here is the commit message:
Validate that X-XSRF-Token and X-XSRF-Token cookie are the
 same - fixes #970 (cherry picked from commit 482bc72)

(cherry picked from commit f42b193)

Here is the root cause:
The bug was caused by the lack of validation to ensure that the X-XSRF-Token in the request header matched the X-XSRF-Token stored in the cookie. This oversight allowed potential CSRF attacks, as there was no check to confirm that both tokens were the same, leading to a security vulnerability.

Here is the patch:

-  private boolean validateToken(String header) {
+  private boolean validateToken(String header, String cookie) {

-    if (header == null) {
+    if (header == null || cookie == null || !header.equals(cookie)) {
       return false;
     }

     String[] tokens = header.split("\\.");
     if (tokens.length != 3) {
       return false;
     }

     String saltPlusToken = tokens[0] + "." + tokens[1];
     String signature = BASE64.encodeToString(mac.doFinal(saltPlusToken.getBytes()));

     if(!signature.equals(tokens[2])) {
       return false;
     }

     try {
       // validate validity
       return !(System.currentTimeMillis() > Long.parseLong(tokens[1]) + timeout);
     } catch (NumberFormatException e) {
       return false;
     }
   }


   @Override
   public void handle(RoutingContext ctx) {

     if (nagHttps) {
       String uri = ctx.request().absoluteURI();
       if (uri != null && !uri.startsWith("https:")) {
         log.warn("Using session cookies without https could make you susceptible to session hijacking: " + uri);
       }
     }

     HttpMethod method = ctx.request().method();

     switch (method) {
       case GET:
         final String token = generateToken();
         // put the token in the context for users who prefer to render the token directly on the HTML
         ctx.put(headerName, token);
         ctx.addCookie(Cookie.cookie(cookieName, token).setPath(cookiePath));
         ctx.next();
         break;
       case POST:
       case PUT:
       case DELETE:
       case PATCH:
         final String header = ctx.request().getHeader(headerName);
-        if (validateToken(header == null ? ctx.request().getFormAttribute(headerName) : header)) {
+        final String cookie = ctx.getCookie(cookieName).getValue();
+        if (validateToken(header == null ? ctx.request().getFormAttribute(headerName) : header, cookie)) {
           ctx.next();
         } else {
           forbidden(ctx);
         }
         break;
       default:
         // ignore these methods
         ctx.next();
         break;
     }
   }
 }


